def kth_ordered(words, k):
    if not words or k <= 0:
        return None

    # Group words by their length
    grouped_words = {}
    for word in words:
        length = len(word)
        if length not in grouped_words:
            grouped_words[length] = []
        grouped_words[length].append(word)

    sorted_words = []
    for length in sorted(grouped_words):
        # Sort groups of equal length reverse-alphabetically
        sorted_group = sorted(grouped_words[length], reverse=True)
        sorted_words.extend(sorted_group)

    if k > len(sorted_words):
        return None

    return sorted_words[k-1]
